import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.join.ExhaustiveLegalJoinSearchContributor;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.join.JoinSearchContributor;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.join.JoinSearchRequest;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.join.JoinSearchService;
import org.junit.jupiter.api.Test;

class CascadesSearchModeRoutingTest {

	@Test
	void shadowUsesCompleteJoinSearch() {
		JoinSearchRequest request = captureRequest(OptimizationGoal.SearchMode.SHADOW, Long.MAX_VALUE,
				Integer.MAX_VALUE);

		assertEquals(JoinSearchRequest.Mode.COMPLETE, request.mode(),
				"SHADOW must observe the same exhaustive join candidate space as EXACT");
		assertEquals(Long.MAX_VALUE, request.candidateBudget());
	}

	@Test
	void shadowBudgetedUsesBoundedJoinSearchAndFiniteCandidateBudget() {
		JoinSearchRequest request = captureRequest(OptimizationGoal.SearchMode.SHADOW_BUDGETED, Long.MAX_VALUE,
				4_096);

		assertEquals(JoinSearchRequest.Mode.BOUNDED, request.mode());
		assertTrue(request.candidateBudget() > 0L);
		assertTrue(request.candidateBudget() < Long.MAX_VALUE,
				"SHADOW_BUDGETED must preserve the bounded search budget instead of inheriting exact search");
	}

	@Test
	void autoUsesDeterministicBoundedJoinSearchDespiteExpiredDeadline() {
		JoinSearchRequest request = captureRequest(OptimizationGoal.SearchMode.AUTO, 1L, 1);

		assertEquals(JoinSearchRequest.Mode.BOUNDED, request.mode());
		assertTrue(request.candidateBudget() > 0L);
		assertTrue(request.candidateBudget() <= SearchLimits.AUTO.candidateEvaluations(),
				"AUTO join search must use its fixed deterministic candidate limit");
	}

	@Test
	void exactSequenceDoesNotRouteReorderableJoinThroughJoinSearch() {
		PhysicalProperties required = PhysicalProperties.builder()
				.observationOrder(PhysicalProperties.ObservationOrder.EXACT_SEQUENCE)
				.build();
		PlannerObservation observation = optimize(twoFactorJoin(), OptimizationGoal.exact(required));

		assertNull(observation.request(),
				"Join search cannot preserve which otherwise-unordered observation sequence was written");
		assertEquals(0L, observation.plan().searchStatus().counters().partitionProbes());
		assertEquals(OptimizationCompleteness.COMPLETE, observation.plan().completeness());
		assertEquals(PhysicalProperties.ObservationOrder.EXACT_SEQUENCE,
				observation.plan().winner().orElseThrow().deliveredProperties().observationOrder());
		Join selected = assertInstanceOf(Join.class, observation.plan().tupleExpr().orElseThrow());
		assertEquals("p1", assertInstanceOf(StatementPattern.class, selected.getLeftArg()).getPredicateVar().getName());
		assertEquals("p2",
				assertInstanceOf(StatementPattern.class, selected.getRightArg()).getPredicateVar().getName());
	}

	private static JoinSearchRequest captureRequest(OptimizationGoal.SearchMode mode, long deadlineNanos,
			int taskBudget) {
		OptimizationGoal goal = new OptimizationGoal(PhysicalProperties.ANY, OptimizationGoal.BAG_SEMANTICS,
				OptimizationGoal.CostPolicy.EXACT, CostVector.INFINITE, Set.of(), mode, deadlineNanos, taskBudget);
		JoinSearchRequest request = optimize(twoFactorJoin(), goal).request();
		assertNotNull(request, "the planner must route the reorderable join through join search");
		return request;
	}

	private static PlannerObservation optimize(Join join, OptimizationGoal goal) {
		AtomicReference<JoinSearchRequest> captured = new AtomicReference<>();
		ExhaustiveLegalJoinSearchContributor delegate = new ExhaustiveLegalJoinSearchContributor();
		JoinSearchContributor observer = new JoinSearchContributor() {
			@Override
			public Descriptor descriptor() {
				return delegate.descriptor();
			}

			@Override
			public Outcome contribute(JoinSearchRequest request, CandidateSink sink) {
				captured.set(request);
				return delegate.contribute(request, sink);
			}

			@Override
			public Outcome contributeMemoExpressions(JoinSearchRequest request, MemoExpressionSink sink) {
				captured.set(request);
				return delegate.contributeMemoExpressions(request, sink);
			}
		};
		CascadesPlanner planner = new CascadesPlanner(CascadesCostModel.from(new EvaluationStatistics()),
				RuleRegistry.builder().add(new StandardCascadesRules.GenericImplementationRule()).build(),
				CascadesTelemetry.NO_OP, 16, RewriteMetadata.empty(), new JoinSearchService(List.of(observer)));

		return new PlannerObservation(planner.optimize(join, goal), captured.get());
	}

	private static Join twoFactorJoin() {
		return new Join(pattern("a", "p1", "b"), pattern("b", "p2", "c"));
	}

	private static StatementPattern pattern(String subject, String predicate, String object) {
		return new StatementPattern(new Var(subject), new Var(predicate), new Var(object));
	}

	private record PlannerObservation(CascadesPlan plan, JoinSearchRequest request) {
	}
}
